### Component Responsibilities

```typescript
interface SystemComponents {
  userInterface: {
    dashboard: 'Real-time fleet status and KPIs';
    scheduleEditor: 'View and modify maintenance schedule';
    whatIfSimulator: 'Scenario planning interface';
    reports: 'Scheduled and ad-hoc reporting';
  };

  apiLayer: {
    scheduleApi: 'CRUD operations on schedules';
    assetApi: 'Asset and maintenance type management';
    analyticsApi: 'Metrics and KPI queries';
    integrationApi: 'External system webhooks';
  };

  serviceLayer: {
    schedulingService: 'Orchestrates schedule generation';
    assetService: 'Asset lifecycle management';
    driftTracker: 'Monitors planned vs actual';
    rucEngine: 'Calculates usage recommendations';
    costingService: 'Cost forecasting and tracking';
  };

  optimizationLayer: {
    solverOrchestrator: 'Manages solver selection and execution';
    highsAdapter: 'HiGHS MIP solver interface';
    cpsatAdapter: 'OR-Tools CP-SAT interface';
    heuristicFallback: 'Fast fallback algorithm';
  };

  dataLayer: {
    postgresql: 'Relational data (assets, schedules)';
    timescaledb: 'Time-series metrics';
    redis: 'Session cache, job queues';
    objectStorage: 'Reports, exports, backups';
  };
}
```

## Data Flow

### Schedule Generation Flow

```typescript
interface ScheduleGenerationFlow {
  step1_request: {
    trigger: 'User action or scheduled job';
    input: 'Schedule parameters, constraints';
    output: 'Job ID for tracking';
  };

  step2_preparation: {
    action: 'Load assets, maintenance types, current state';
    source: 'PostgreSQL';
    output: 'Problem instance';
  };

  step3_optimization: {
    action: 'Solve scheduling problem';
    solver: 'HiGHS or CP-SAT via orchestrator';
    timeout: '60-300 seconds typical';
    output: 'Optimized schedule';
  };

  step4_validation: {
    action: 'Verify constraints satisfied';
    checks: ['Capacity', 'Time windows', 'Precedence'];
    output: 'Validated schedule or errors';
  };

  step5_persistence: {
    action: 'Store schedule and metrics';
    destination: 'PostgreSQL';
    sideEffects: ['Invalidate caches', 'Trigger notifications'];
  };

  step6_response: {
    action: 'Return result to caller';
    content: 'Schedule summary and access URL';
  };
}
```

### Real-Time Monitoring Flow

```typescript
interface MonitoringFlow {
  dataIngestion: {
    sources: ['Telematics', 'Manual entry', 'EAM webhooks'];
    frequency: 'Hourly to real-time';
    destination: 'TimescaleDB';
  };

  driftCalculation: {
    trigger: 'New mileage data received';
    calculation: 'Actual - Planned mileage';
    storage: 'Asset drift metrics';
  };

  rucGeneration: {
    trigger: 'Daily or on drift threshold';
    calculation: 'Categorize assets by drift';
    output: 'ACCELERATE/NOMINAL/DECELERATE';
  };

  alerting: {
    trigger: 'Threshold breaches';
    channels: ['Email', 'Dashboard', 'Webhook'];
    examples: ['Drift > 10%', 'Maintenance overdue'];
  };
}
```

## Key Design Principles

### Separation of Concerns

```typescript
interface SeparationOfConcerns {
  principle: 'Each component has single responsibility';

  examples: {
    solverOrchestrator: 'Only manages solver execution';
    assetService: 'Only manages asset data';
    apiLayer: 'Only handles HTTP concerns';
  };

  benefits: [
    'Easier testing',
    'Independent deployment',
    'Clear ownership'
  ];
}
```

### Solver Abstraction

```typescript
interface SolverAbstraction {
  principle: 'Business logic independent of solver choice';

  implementation: {
    interface: 'Common SolverAdapter interface';
    adapters: ['HiGHSAdapter', 'CPSATAdapter', 'HeuristicAdapter'];
    selection: 'Runtime based on problem characteristics';
  };

  benefits: [
    'Switch solvers without code changes',
    'A/B test solver performance',
    'Fallback on solver failures'
  ];
}

interface SolverAdapter {
  solve(problem: SchedulingProblem): Promise<ScheduleSolution>;
  interrupt(): void;
  getStatus(): SolverStatus;
}

class HiGHSAdapter implements SolverAdapter {
  async solve(problem: SchedulingProblem): Promise<ScheduleSolution> {
    // Convert to HiGHS model and solve
  }
}

class CPSATAdapter implements SolverAdapter {
  async solve(problem: SchedulingProblem): Promise<ScheduleSolution> {
    // Convert to CP-SAT model and solve
  }
}
```

### Event-Driven Updates

```typescript
interface EventDrivenDesign {
  principle: 'React to changes asynchronously';

  events: {
    assetMileageUpdated: 'Triggers drift recalculation';
    scheduleGenerated: 'Triggers notification and cache update';
    maintenanceCompleted: 'Triggers next event scheduling';
  };

  implementation: {
    broker: 'Redis pub/sub or message queue';
    handlers: 'Idempotent event processors';
    retry: 'Dead letter queue for failures';
  };
}
```

### Horizontal Scalability

```typescript
interface ScalabilityDesign {
  principle: 'Scale out by adding instances';

  stateless: {
    apiServers: 'Any instance can handle any request';
    session: 'Stored in Redis, not memory';
  };

  stateful: {
    database: 'Single source of truth';
    solverJobs: 'Queued and processed by workers';
  };

  scaling: {
    readHeavy: 'Add read replicas';
    writeHeavy: 'Partition by tenant/fleet';
    computeHeavy: 'Scale solver workers';
  };
}
```

