    12вҶ’# RUC (Recommended Usage Category) System
    13вҶ’
    14вҶ’This document covers the RUC system, which categorizes assets based on their actual usage compared to planned usage, enabling proactive schedule adjustments.
    15вҶ’
    16вҶ’## RUC System Overview
    17вҶ’
    18вҶ’### What is RUC?
    19вҶ’
    20вҶ’```typescript
    21вҶ’interface RUCSystem {
    22вҶ’  definition: 'A categorization system for asset usage patterns';
    23вҶ’  purpose: 'Identify assets that need schedule adjustments';
    24вҶ’
    25вҶ’  categories: {
    26вҶ’    ACCELERATE: 'Usage higher than planned - schedule maintenance earlier';
    27вҶ’    NOMINAL: 'Usage within expected range - no adjustment needed';
    28вҶ’    DECELERATE: 'Usage lower than planned - schedule maintenance later';
    29вҶ’  };
    30вҶ’
    31вҶ’  benefits: [
    32вҶ’    'Proactive maintenance planning',
    33вҶ’    'Reduced maintenance drift',
    34вҶ’    'Better resource allocation',
    35вҶ’    'Improved asset availability'
    36вҶ’  ];
    37вҶ’}
    38вҶ’```
    39вҶ’
    40вҶ’### RUC Categories
    41вҶ’
    42вҶ’```typescript
    43вҶ’enum RUCCategory {
    44вҶ’  ACCELERATE = 'ACCELERATE',
    45вҶ’  NOMINAL = 'NOMINAL',
    46вҶ’  DECELERATE = 'DECELERATE'
    47вҶ’}
    48вҶ’
    49вҶ’interface RUCThresholds {
    50вҶ’  accelerateThreshold: number;  // e.g., 1.10 (10% above plan)
    51вҶ’  decelerateThreshold: number;  // e.g., 0.90 (10% below plan)
    52вҶ’
    53вҶ’  // Category determined by: actualUsage / plannedUsage
    54вҶ’  // > accelerateThreshold -> ACCELERATE
    55вҶ’  // < decelerateThreshold -> DECELERATE
    56вҶ’  // else -> NOMINAL
    57вҶ’}
    58вҶ’
    59вҶ’const defaultThresholds: RUCThresholds = {
    60вҶ’  accelerateThreshold: 1.10,
    61вҶ’  decelerateThreshold: 0.90
    62вҶ’};
    63вҶ’```
    64вҶ’
    65вҶ’## RUC Calculation
    66вҶ’
    67вҶ’### Basic Calculation
    68вҶ’
    69вҶ’```typescript
    70вҶ’interface RUCCalculationInput {
    71вҶ’  assetId: string;
    72вҶ’  currentMileage: number;
    73вҶ’  plannedMileage: number;
    74вҶ’  calculationDate: Date;
    75вҶ’}
    76вҶ’
    77вҶ’interface RUCResult {
    78вҶ’  assetId: string;
    79вҶ’  category: RUCCategory;
    80вҶ’  ratio: number;
    81вҶ’  deviation: number;
    82вҶ’  absoluteDeviation: number;
    83вҶ’  calculatedAt: Date;
    84вҶ’}
    85вҶ’
    86вҶ’function calculateRUC(
    87вҶ’  input: RUCCalculationInput,
    88вҶ’  thresholds: RUCThresholds
    89вҶ’): RUCResult {
    90вҶ’  const ratio = input.currentMileage / input.plannedMileage;
    91вҶ’  const deviation = ratio - 1;
    92вҶ’  const absoluteDeviation = input.currentMileage - input.plannedMileage;
    93вҶ’
    94вҶ’  let category: RUCCategory;
    95вҶ’
    96вҶ’  if (ratio > thresholds.accelerateThreshold) {
    97вҶ’    category = RUCCategory.ACCELERATE;
    98вҶ’  } else if (ratio < thresholds.decelerateThreshold) {
    99вҶ’    category = RUCCategory.DECELERATE;
   100вҶ’  } else {
   101вҶ’    category = RUCCategory.NOMINAL;
   102вҶ’  }
   103вҶ’
   104вҶ’  return {
   105вҶ’    assetId: input.assetId,
   106вҶ’    category,
   107вҶ’    ratio,
   108вҶ’    deviation,
   109вҶ’    absoluteDeviation,
   110вҶ’    calculatedAt: input.calculationDate
   111вҶ’  };
   112вҶ’}
   113вҶ’```
   114вҶ’
   115вҶ’### Planned Mileage Calculation
   116вҶ’
   117вҶ’```typescript
   118вҶ’interface PlannedMileageInput {
   119вҶ’  assetId: string;
   120вҶ’  scheduleStartDate: Date;
   121вҶ’  currentDate: Date;
   122вҶ’  targetMileageAtScheduleEnd: number;
   123вҶ’  scheduleEndDate: Date;
   124вҶ’}
   125вҶ’
   126вҶ’function calculatePlannedMileage(input: PlannedMileageInput): number {
   127вҶ’  const totalScheduleDays = daysBetween(
   128вҶ’    input.scheduleStartDate,
   129вҶ’    input.scheduleEndDate
   130вҶ’  );
   131вҶ’  const elapsedDays = daysBetween(
   132вҶ’    input.scheduleStartDate,
   133вҶ’    input.currentDate
   134вҶ’  );
   135вҶ’
   136вҶ’  // Linear interpolation
   137вҶ’  const progress = elapsedDays / totalScheduleDays;
   138вҶ’  const plannedMileage = input.targetMileageAtScheduleEnd * progress;
   139вҶ’
   140вҶ’  return Math.round(plannedMileage);
   141вҶ’}
   142вҶ’
   143вҶ’// Alternative: Use baseline from historical data
   144вҶ’function calculatePlannedMileageFromBaseline(
   145вҶ’  assetId: string,
   146вҶ’  baselineDailyRate: number,
   147вҶ’  scheduleStartDate: Date,
   148вҶ’  currentDate: Date,
   149вҶ’  startMileage: number
   150вҶ’): number {
   151вҶ’  const elapsedDays = daysBetween(scheduleStartDate, currentDate);
   152вҶ’  return startMileage + (baselineDailyRate * elapsedDays);
   153вҶ’}
   154вҶ’```
   155вҶ’
   156вҶ’### Batch RUC Calculation
   157вҶ’
   158вҶ’```typescript
   159вҶ’interface BatchRUCInput {
   160вҶ’  assets: Asset[];
   161вҶ’  scheduleEvents: ScheduledEvent[];
   162вҶ’  currentDate: Date;
   163вҶ’  thresholds: RUCThresholds;
   164вҶ’}
   165вҶ’
   166вҶ’async function calculateBatchRUC(
   167вҶ’  input: BatchRUCInput
   168вҶ’): Promise<Map<string, RUCResult>> {
   169вҶ’  const results = new Map<string, RUCResult>();
   170вҶ’
   171вҶ’  for (const asset of input.assets) {
   172вҶ’    // Find next scheduled event for this asset
   173вҶ’    const nextEvent = input.scheduleEvents
   174вҶ’      .filter(e => e.assetId === asset.id && e.status === 'scheduled')
   175вҶ’      .sort((a, b) => a.scheduledPeriod - b.scheduledPeriod)[0];
   176вҶ’
   177вҶ’    if (!nextEvent) continue;
   178вҶ’
   179вҶ’    // Calculate planned mileage at current date
   180вҶ’    const plannedMileage = interpolatePlannedMileage(
   181вҶ’      asset,
   182вҶ’      nextEvent,
   183вҶ’      input.currentDate
   184вҶ’    );
   185вҶ’
   186вҶ’    const rucResult = calculateRUC(
   187вҶ’      {
   188вҶ’        assetId: asset.id,
   189вҶ’        currentMileage: asset.currentMileage,
   190вҶ’        plannedMileage,
   191вҶ’        calculationDate: input.currentDate
   192вҶ’      },
   193вҶ’      input.thresholds
   194вҶ’    );
   195вҶ’
   196вҶ’    results.set(asset.id, rucResult);
   197вҶ’  }
   198вҶ’
   199вҶ’  return results;
   200вҶ’}
   201вҶ’```
   202вҶ’
   203вҶ’## Advanced RUC Models
   204вҶ’
   205вҶ’### Weighted Moving Average RUC
   206вҶ’
   207вҶ’```typescript
   208вҶ’interface WeightedRUCConfig {
   209вҶ’  windowSize: number;  // Number of periods to consider
   210вҶ’  weights: number[];   // Weights for each period (recent = higher)
   211вҶ’}
   212вҶ’
   213вҶ’function calculateWeightedRUC(
   214вҶ’  historicalRatios: number[],
   215вҶ’  config: WeightedRUCConfig,
   216вҶ’  thresholds: RUCThresholds
   217вҶ’): RUCCategory {
   218вҶ’  // Ensure we have enough data
   219вҶ’  const ratios = historicalRatios.slice(-config.windowSize);
   220вҶ’
   221вҶ’  if (ratios.length < config.windowSize) {
   222вҶ’    // Pad with 1.0 (nominal) for missing data
   223вҶ’    while (ratios.length < config.windowSize) {
   224вҶ’      ratios.unshift(1.0);
   225вҶ’    }
   226вҶ’  }
   227вҶ’
   228вҶ’  // Normalize weights
   229вҶ’  const totalWeight = config.weights.reduce((a, b) => a + b, 0);
   230вҶ’  const normalizedWeights = config.weights.map(w => w / totalWeight);
   231вҶ’
   232вҶ’  // Calculate weighted average
   233вҶ’  let weightedSum = 0;
   234вҶ’  for (let i = 0; i < config.windowSize; i++) {
   235вҶ’    weightedSum += ratios[i] * normalizedWeights[i];
   236вҶ’  }
   237вҶ’
   238вҶ’  if (weightedSum > thresholds.accelerateThreshold) {
   239вҶ’    return RUCCategory.ACCELERATE;
   240вҶ’  } else if (weightedSum < thresholds.decelerateThreshold) {
   241вҶ’    return RUCCategory.DECELERATE;
   242вҶ’  }
   243вҶ’
   244вҶ’  return RUCCategory.NOMINAL;
   245вҶ’}
   246вҶ’
   247вҶ’// Example configuration with exponential weights
   248вҶ’const exponentialWeights: WeightedRUCConfig = {
   249вҶ’  windowSize: 4,
   250вҶ’  weights: [1, 2, 4, 8]  // Most recent period has highest weight
   251вҶ’};
   252вҶ’```
   253вҶ’
   254вҶ’### Seasonal RUC Adjustment
   255вҶ’
   256вҶ’```typescript
   257вҶ’interface SeasonalFactor {
   258вҶ’  month: number;  // 1-12
   259вҶ’  factor: number; // Multiplier (e.g., 1.2 for 20% higher usage)
   260вҶ’}
   261вҶ’
   262вҶ’interface SeasonalRUCConfig {
   263вҶ’  baseThresholds: RUCThresholds;
   264вҶ’  seasonalFactors: SeasonalFactor[];
   265вҶ’}
   266вҶ’
   267вҶ’function calculateSeasonalRUC(
   268вҶ’  currentMileage: number,
   269вҶ’  plannedMileage: number,
   270вҶ’  currentDate: Date,
   271вҶ’  config: SeasonalRUCConfig
   272вҶ’): RUCCategory {
   273вҶ’  const month = currentDate.getMonth() + 1;
   274вҶ’
   275вҶ’  // Find seasonal factor for current month
   276вҶ’  const seasonalFactor = config.seasonalFactors.find(f => f.month === month);
   277вҶ’  const factor = seasonalFactor?.factor ?? 1.0;
   278вҶ’
   279вҶ’  // Adjust thresholds based on season
   280вҶ’  const adjustedThresholds: RUCThresholds = {
   281вҶ’    accelerateThreshold: config.baseThresholds.accelerateThreshold * factor,
   282вҶ’    decelerateThreshold: config.baseThresholds.decelerateThreshold * factor
   283вҶ’  };
   284вҶ’
   285вҶ’  const ratio = currentMileage / plannedMileage;
   286вҶ’
   287вҶ’  if (ratio > adjustedThresholds.accelerateThreshold) {
   288вҶ’    return RUCCategory.ACCELERATE;
   289вҶ’  } else if (ratio < adjustedThresholds.decelerateThreshold) {
   290вҶ’    return RUCCategory.DECELERATE;
   291вҶ’  }
   292вҶ’
   293вҶ’  return RUCCategory.NOMINAL;
   294вҶ’}
   295вҶ’
   296вҶ’// Example: Higher thresholds in summer (more usage expected)
   297вҶ’const seasonalConfig: SeasonalRUCConfig = {
   298вҶ’  baseThresholds: { accelerateThreshold: 1.10, decelerateThreshold: 0.90 },
   299вҶ’  seasonalFactors: [
   300вҶ’    { month: 6, factor: 1.15 },   // June
   301вҶ’    { month: 7, factor: 1.20 },   // July
   302вҶ’    { month: 8, factor: 1.15 },   // August
   303вҶ’    { month: 12, factor: 0.85 },  // December
   304вҶ’    { month: 1, factor: 0.90 }    // January
   305вҶ’  ]
   306вҶ’};
   307вҶ’```
   308вҶ’
   309вҶ’### Trend-Based RUC
   310вҶ’
   311вҶ’```typescript
   312вҶ’interface TrendRUCResult {
   313вҶ’  category: RUCCategory;
   314вҶ’  trend: 'increasing' | 'stable' | 'decreasing';
   315вҶ’  predictedCategory: RUCCategory;  // Where the asset is heading
   316вҶ’  confidence: number;
   317вҶ’}
   318вҶ’
   319вҶ’function calculateTrendRUC(
   320вҶ’  historicalRatios: Array<{ date: Date; ratio: number }>,
   321вҶ’  thresholds: RUCThresholds
   322вҶ’): TrendRUCResult {
   323вҶ’  // Sort by date
   324вҶ’  const sorted = historicalRatios.sort(
   325вҶ’    (a, b) => a.date.getTime() - b.date.getTime()
   326вҶ’  );
   327вҶ’
   328вҶ’  // Current category based on latest ratio
   329вҶ’  const currentRatio = sorted[sorted.length - 1].ratio;
   330вҶ’  const currentCategory = getRUCCategory(currentRatio, thresholds);
   331вҶ’
   332вҶ’  // Calculate trend using linear regression
   333вҶ’  const n = sorted.length;
   334вҶ’  const x = sorted.map((_, i) => i);
   335вҶ’  const y = sorted.map(s => s.ratio);
   336вҶ’
   337вҶ’  const sumX = x.reduce((a, b) => a + b, 0);
   338вҶ’  const sumY = y.reduce((a, b) => a + b, 0);
   339вҶ’  const sumXY = x.reduce((sum, xi, i) => sum + xi * y[i], 0);
   340вҶ’  const sumX2 = x.reduce((sum, xi) => sum + xi * xi, 0);
   341вҶ’
   342вҶ’  const slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);
   343вҶ’
   344вҶ’  // Determine trend
   345вҶ’  let trend: 'increasing' | 'stable' | 'decreasing';
   346вҶ’  if (slope > 0.01) {
   347вҶ’    trend = 'increasing';
   348вҶ’  } else if (slope < -0.01) {
   349вҶ’    trend = 'decreasing';
   350вҶ’  } else {
   351вҶ’    trend = 'stable';
   352вҶ’  }
   353вҶ’
   354вҶ’  // Predict future category (extrapolate 4 periods)
   355вҶ’  const predictedRatio = currentRatio + (slope * 4);
   356вҶ’  const predictedCategory = getRUCCategory(predictedRatio, thresholds);
   357вҶ’
   358вҶ’  // Calculate confidence based on R-squared
   359вҶ’  const meanY = sumY / n;
   360вҶ’  const ssTotal = y.reduce((sum, yi) => sum + Math.pow(yi - meanY, 2), 0);
   361вҶ’  const predicted = x.map(xi => meanY + slope * (xi - sumX / n));
   362вҶ’  const ssResidual = y.reduce((sum, yi, i) => sum + Math.pow(yi - predicted[i], 2), 0);
   363вҶ’  const rSquared = 1 - (ssResidual / ssTotal);
   364вҶ’
   365вҶ’  return {
   366вҶ’    category: currentCategory,
   367вҶ’    trend,
   368вҶ’    predictedCategory,
   369вҶ’    confidence: Math.max(0, Math.min(1, rSquared))
   370вҶ’  };
   371вҶ’}
   372вҶ’```
   373вҶ’
   374вҶ’## RUC Service Implementation
   375вҶ’
   376вҶ’### Core Service
   377вҶ’
   378вҶ’```typescript
   379вҶ’// services/ruc.service.ts
   380вҶ’export class RUCService {
   381вҶ’  constructor(
   382вҶ’    private readonly assetRepo: AssetRepository,
   383вҶ’    private readonly scheduleRepo: ScheduleRepository,
   384вҶ’    private readonly mileageRepo: MileageRepository,
   385вҶ’    private readonly rucRepo: RUCRepository
   386вҶ’  ) {}
   387вҶ’
   388вҶ’  async calculateCurrentRUC(
   389вҶ’    assetIds?: string[]
   390вҶ’  ): Promise<Map<string, RUCResult>> {
   391вҶ’    // Get assets
   392вҶ’    const assets = assetIds
   393вҶ’      ? await this.assetRepo.findByIds(assetIds)
   394вҶ’      : await this.assetRepo.findActive();
   395вҶ’
   396вҶ’    // Get active schedule
   397вҶ’    const schedule = await this.scheduleRepo.getPublished();
   398вҶ’    if (!schedule) {
   399вҶ’      throw new Error('No published schedule found');
   400вҶ’    }
   401вҶ’
   402вҶ’    // Get thresholds from config
   403вҶ’    const thresholds = await this.getThresholds();
   404вҶ’
   405вҶ’    // Calculate RUC for each asset
   406вҶ’    const results = await calculateBatchRUC({
   407вҶ’      assets,
   408вҶ’      scheduleEvents: schedule.events,
   409вҶ’      currentDate: new Date(),
   410вҶ’      thresholds
   411вҶ’    });
   412вҶ’
   413вҶ’    // Store results
   414вҶ’    await this.storeRUCResults(results, schedule.id);
   415вҶ’
   416вҶ’    return results;
   417вҶ’  }
   418вҶ’
   419вҶ’  async getRUCHistory(
   420вҶ’    assetId: string,
   421вҶ’    startDate: Date,
   422вҶ’    endDate: Date
   423вҶ’  ): Promise<RUCResult[]> {
   424вҶ’    return this.rucRepo.getHistory(assetId, startDate, endDate);
   425вҶ’  }
   426вҶ’
   427вҶ’  async getRUCDistribution(): Promise<RUCDistribution> {
   428вҶ’    const results = await this.calculateCurrentRUC();
   429вҶ’
   430вҶ’    let accelerate = 0, nominal = 0, decelerate = 0;
   431вҶ’
   432вҶ’    for (const [, result] of results) {
   433вҶ’      switch (result.category) {
   434вҶ’        case RUCCategory.ACCELERATE:
   435вҶ’          accelerate++;
   436вҶ’          break;
   437вҶ’        case RUCCategory.NOMINAL:
   438вҶ’          nominal++;
   439вҶ’          break;
   440вҶ’        case RUCCategory.DECELERATE:
   441вҶ’          decelerate++;
   442вҶ’          break;
   443вҶ’      }
   444вҶ’    }
   445вҶ’
   446вҶ’    const total = results.size;
   447вҶ’
   448вҶ’    return {
   449вҶ’      accelerate: { count: accelerate, percentage: accelerate / total },
   450вҶ’      nominal: { count: nominal, percentage: nominal / total },
   451вҶ’      decelerate: { count: decelerate, percentage: decelerate / total },
   452вҶ’      total
   453вҶ’    };
   454вҶ’  }
   455вҶ’
   456вҶ’  private async storeRUCResults(
   457вҶ’    results: Map<string, RUCResult>,
   458вҶ’    scheduleId: string
   459вҶ’  ): Promise<void> {
   460вҶ’    const records = Array.from(results.values()).map(result => ({
   461вҶ’      assetId: result.assetId,
   462вҶ’      scheduleId,
   463вҶ’      category: result.category,
   464вҶ’      ratio: result.ratio,
   465вҶ’      deviation: result.deviation,
   466вҶ’      absoluteDeviation: result.absoluteDeviation,
   467вҶ’      calculatedAt: result.calculatedAt
   468вҶ’    }));
   469вҶ’
   470вҶ’    await this.rucRepo.createBatch(records);
   471вҶ’  }
   472вҶ’}
   473вҶ’```
