   475вҶ’### Scheduled RUC Calculation
   476вҶ’
   477вҶ’```typescript
   478вҶ’// jobs/ruc-calculation.job.ts
   479вҶ’export class RUCCalculationJob {
   480вҶ’  constructor(
   481вҶ’    private readonly rucService: RUCService,
   482вҶ’    private readonly alertService: AlertService,
   483вҶ’    private readonly notificationService: NotificationService
   484вҶ’  ) {}
   485вҶ’
   486вҶ’  @Cron('0 6 * * *')  // Daily at 6 AM
   487вҶ’  async runDailyRUCCalculation(): Promise<void> {
   488вҶ’    console.log('Starting daily RUC calculation...');
   489вҶ’
   490вҶ’    try {
   491вҶ’      const results = await this.rucService.calculateCurrentRUC();
   492вҶ’
   493вҶ’      // Check for significant changes
   494вҶ’      const alerts = await this.checkForAlerts(results);
   495вҶ’
   496вҶ’      if (alerts.length > 0) {
   497вҶ’        await this.alertService.createBatch(alerts);
   498вҶ’        await this.notificationService.sendRUCAlerts(alerts);
   499вҶ’      }
   500вҶ’
   501вҶ’      console.log(`RUC calculation complete. ${results.size} assets processed.`);
   502вҶ’    } catch (error) {
   503вҶ’      console.error('RUC calculation failed:', error);
   504вҶ’      throw error;
   505вҶ’    }
   506вҶ’  }
   507вҶ’
   508вҶ’  private async checkForAlerts(
   509вҶ’    results: Map<string, RUCResult>
   510вҶ’  ): Promise<RUCAlert[]> {
   511вҶ’    const alerts: RUCAlert[] = [];
   512вҶ’
   513вҶ’    // Get previous RUC results for comparison
   514вҶ’    const previousResults = await this.rucService.getPreviousResults();
   515вҶ’
   516вҶ’    for (const [assetId, current] of results) {
   517вҶ’      const previous = previousResults.get(assetId);
   518вҶ’
   519вҶ’      // Alert on category change
   520вҶ’      if (previous && previous.category !== current.category) {
   521вҶ’        alerts.push({
   522вҶ’          type: 'category_change',
   523вҶ’          assetId,
   524вҶ’          previousCategory: previous.category,
   525вҶ’          currentCategory: current.category,
   526вҶ’          ratio: current.ratio,
   527вҶ’          severity: this.calculateSeverity(previous, current)
   528вҶ’        });
   529вҶ’      }
   530вҶ’
   531вҶ’      // Alert on high deviation
   532вҶ’      if (Math.abs(current.deviation) > 0.20) {
   533вҶ’        alerts.push({
   534вҶ’          type: 'high_deviation',
   535вҶ’          assetId,
   536вҶ’          category: current.category,
   537вҶ’          deviation: current.deviation,
   538вҶ’          severity: Math.abs(current.deviation) > 0.30 ? 'critical' : 'warning'
   539вҶ’        });
   540вҶ’      }
   541вҶ’    }
   542вҶ’
   543вҶ’    return alerts;
   544вҶ’  }
   545вҶ’}
   546вҶ’```
   547вҶ’
   548вҶ’## RUC-Based Schedule Adjustment
   549вҶ’
   550вҶ’### Automatic Adjustment Rules
   551вҶ’
   552вҶ’```typescript
   553вҶ’interface RUCAdjustmentRule {
   554вҶ’  category: RUCCategory;
   555вҶ’  minRatio: number;
   556вҶ’  maxRatio: number;
   557вҶ’  periodAdjustment: number;  // Positive = move later, negative = move earlier
   558вҶ’}
   559вҶ’
   560вҶ’const defaultAdjustmentRules: RUCAdjustmentRule[] = [
   561вҶ’  // ACCELERATE: Move maintenance earlier
   562вҶ’  { category: RUCCategory.ACCELERATE, minRatio: 1.10, maxRatio: 1.20, periodAdjustment: -1 },
   563вҶ’  { category: RUCCategory.ACCELERATE, minRatio: 1.20, maxRatio: 1.30, periodAdjustment: -2 },
   564вҶ’  { category: RUCCategory.ACCELERATE, minRatio: 1.30, maxRatio: Infinity, periodAdjustment: -3 },
   565вҶ’
   566вҶ’  // DECELERATE: Move maintenance later
   567вҶ’  { category: RUCCategory.DECELERATE, minRatio: 0.80, maxRatio: 0.90, periodAdjustment: 1 },
   568вҶ’  { category: RUCCategory.DECELERATE, minRatio: 0.70, maxRatio: 0.80, periodAdjustment: 2 },
   569вҶ’  { category: RUCCategory.DECELERATE, minRatio: 0, maxRatio: 0.70, periodAdjustment: 3 }
   570вҶ’];
   571вҶ’
   572вҶ’function calculateAdjustment(
   573вҶ’  rucResult: RUCResult,
   574вҶ’  rules: RUCAdjustmentRule[]
   575вҶ’): number {
   576вҶ’  const applicableRule = rules.find(
   577вҶ’    rule => rule.category === rucResult.category &&
   578вҶ’            rucResult.ratio >= rule.minRatio &&
   579вҶ’            rucResult.ratio < rule.maxRatio
   580вҶ’  );
   581вҶ’
   582вҶ’  return applicableRule?.periodAdjustment ?? 0;
   583вҶ’}
   584вҶ’```
   585вҶ’
   586вҶ’### Schedule Adjustment Service
   587вҶ’
   588вҶ’```typescript
   589вҶ’// services/ruc-adjustment.service.ts
   590вҶ’export class RUCAdjustmentService {
   591вҶ’  async proposeAdjustments(
   592вҶ’    scheduleId: string
   593вҶ’  ): Promise<ProposedAdjustment[]> {
   594вҶ’    const schedule = await this.scheduleRepo.getWithEvents(scheduleId);
   595вҶ’    const rucResults = await this.rucService.calculateCurrentRUC();
   596вҶ’
   597вҶ’    const proposals: ProposedAdjustment[] = [];
   598вҶ’
   599вҶ’    for (const event of schedule.events) {
   600вҶ’      if (event.status !== 'scheduled') continue;
   601вҶ’
   602вҶ’      const ruc = rucResults.get(event.assetId);
   603вҶ’      if (!ruc || ruc.category === RUCCategory.NOMINAL) continue;
   604вҶ’
   605вҶ’      const adjustment = calculateAdjustment(ruc, defaultAdjustmentRules);
   606вҶ’      if (adjustment === 0) continue;
   607вҶ’
   608вҶ’      const newPeriod = event.scheduledPeriod + adjustment;
   609вҶ’
   610вҶ’      // Check if adjustment is within allowed window
   611вҶ’      if (newPeriod < event.earliestPeriod || newPeriod > event.latestPeriod) {
   612вҶ’        continue;  // Cannot adjust outside window
   613вҶ’      }
   614вҶ’
   615вҶ’      proposals.push({
   616вҶ’        eventId: event.id,
   617вҶ’        assetId: event.assetId,
   618вҶ’        currentPeriod: event.scheduledPeriod,
   619вҶ’        proposedPeriod: newPeriod,
   620вҶ’        rucCategory: ruc.category,
   621вҶ’        rucRatio: ruc.ratio,
   622вҶ’        adjustment,
   623вҶ’        reason: this.generateReason(ruc, adjustment)
   624вҶ’      });
   625вҶ’    }
   626вҶ’
   627вҶ’    // Sort by priority (higher deviation = higher priority)
   628вҶ’    proposals.sort((a, b) =>
   629вҶ’      Math.abs(b.rucRatio - 1) - Math.abs(a.rucRatio - 1)
   630вҶ’    );
   631вҶ’
   632вҶ’    return proposals;
   633вҶ’  }
   634вҶ’
   635вҶ’  async applyAdjustments(
   636вҶ’    scheduleId: string,
   637вҶ’    adjustmentIds: string[]
   638вҶ’  ): Promise<AdjustmentResult> {
   639вҶ’    const proposals = await this.proposeAdjustments(scheduleId);
   640вҶ’
   641вҶ’    const toApply = proposals.filter(p => adjustmentIds.includes(p.eventId));
   642вҶ’
   643вҶ’    // Validate adjustments don't violate capacity
   644вҶ’    const validation = await this.validateAdjustments(scheduleId, toApply);
   645вҶ’
   646вҶ’    if (!validation.valid) {
   647вҶ’      return {
   648вҶ’        success: false,
   649вҶ’        errors: validation.errors
   650вҶ’      };
   651вҶ’    }
   652вҶ’
   653вҶ’    // Apply in transaction
   654вҶ’    await this.scheduleRepo.transaction(async (tx) => {
   655вҶ’      for (const adj of toApply) {
   656вҶ’        await this.scheduleRepo.updateEvent(adj.eventId, {
   657вҶ’          scheduledPeriod: adj.proposedPeriod,
   658вҶ’          originalPeriod: adj.currentPeriod,
   659вҶ’          adjustmentReason: adj.reason,
   660вҶ’          adjustmentType: 'ruc_based',
   661вҶ’          adjustedAt: new Date()
   662вҶ’        }, tx);
   663вҶ’      }
   664вҶ’    });
   665вҶ’
   666вҶ’    return {
   667вҶ’      success: true,
   668вҶ’      adjustedCount: toApply.length
   669вҶ’    };
   670вҶ’  }
   671вҶ’
   672вҶ’  private generateReason(ruc: RUCResult, adjustment: number): string {
   673вҶ’    const direction = adjustment < 0 ? 'earlier' : 'later';
   674вҶ’    const deviation = ((ruc.ratio - 1) * 100).toFixed(1);
   675вҶ’
   676вҶ’    return `RUC ${ruc.category}: Asset usage ${deviation}% ` +
   677вҶ’           `${ruc.ratio > 1 ? 'above' : 'below'} plan. ` +
   678вҶ’           `Moving maintenance ${Math.abs(adjustment)} period(s) ${direction}.`;
   679вҶ’  }
   680вҶ’}
   681вҶ’```
