### Trend-Based RUC

```typescript
interface TrendRUCResult {
  category: RUCCategory;
  trend: 'increasing' | 'stable' | 'decreasing';
  predictedCategory: RUCCategory;  // Where the asset is heading
  confidence: number;
}

function calculateTrendRUC(
  historicalRatios: Array<{ date: Date; ratio: number }>,
  thresholds: RUCThresholds
): TrendRUCResult {
  // Sort by date
  const sorted = historicalRatios.sort(
    (a, b) => a.date.getTime() - b.date.getTime()
  );

  // Current category based on latest ratio
  const currentRatio = sorted[sorted.length - 1].ratio;
  const currentCategory = getRUCCategory(currentRatio, thresholds);

  // Calculate trend using linear regression
  const n = sorted.length;
  const x = sorted.map((_, i) => i);
  const y = sorted.map(s => s.ratio);

  const sumX = x.reduce((a, b) => a + b, 0);
  const sumY = y.reduce((a, b) => a + b, 0);
  const sumXY = x.reduce((sum, xi, i) => sum + xi * y[i], 0);
  const sumX2 = x.reduce((sum, xi) => sum + xi * xi, 0);

  const slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);

  // Determine trend
  let trend: 'increasing' | 'stable' | 'decreasing';
  if (slope > 0.01) {
    trend = 'increasing';
  } else if (slope < -0.01) {
    trend = 'decreasing';
  } else {
    trend = 'stable';
  }

  // Predict future category (extrapolate 4 periods)
  const predictedRatio = currentRatio + (slope * 4);
  const predictedCategory = getRUCCategory(predictedRatio, thresholds);

  // Calculate confidence based on R-squared
  const meanY = sumY / n;
  const ssTotal = y.reduce((sum, yi) => sum + Math.pow(yi - meanY, 2), 0);
  const predicted = x.map(xi => meanY + slope * (xi - sumX / n));
  const ssResidual = y.reduce((sum, yi, i) => sum + Math.pow(yi - predicted[i], 2), 0);
  const rSquared = 1 - (ssResidual / ssTotal);

  return {
    category: currentCategory,
    trend,
    predictedCategory,
    confidence: Math.max(0, Math.min(1, rSquared))
  };
}
```

## RUC Service Implementation

### Core Service

```typescript
// services/ruc.service.ts
export class RUCService {
  constructor(
    private readonly assetRepo: AssetRepository,
    private readonly scheduleRepo: ScheduleRepository,
    private readonly mileageRepo: MileageRepository,
    private readonly rucRepo: RUCRepository
  ) {}

  async calculateCurrentRUC(
    assetIds?: string[]
  ): Promise<Map<string, RUCResult>> {
    // Get assets
    const assets = assetIds
      ? await this.assetRepo.findByIds(assetIds)
      : await this.assetRepo.findActive();

    // Get active schedule
    const schedule = await this.scheduleRepo.getPublished();
    if (!schedule) {
      throw new Error('No published schedule found');
    }

    // Get thresholds from config
    const thresholds = await this.getThresholds();

    // Calculate RUC for each asset
    const results = await calculateBatchRUC({
      assets,
      scheduleEvents: schedule.events,
      currentDate: new Date(),
      thresholds
    });

    // Store results
    await this.storeRUCResults(results, schedule.id);

    return results;
  }

  async getRUCHistory(
    assetId: string,
    startDate: Date,
    endDate: Date
  ): Promise<RUCResult[]> {
    return this.rucRepo.getHistory(assetId, startDate, endDate);
  }

  async getRUCDistribution(): Promise<RUCDistribution> {
    const results = await this.calculateCurrentRUC();

    let accelerate = 0, nominal = 0, decelerate = 0;

    for (const [, result] of results) {
      switch (result.category) {
        case RUCCategory.ACCELERATE:
          accelerate++;
          break;
        case RUCCategory.NOMINAL:
          nominal++;
          break;
        case RUCCategory.DECELERATE:
          decelerate++;
          break;
      }
    }

    const total = results.size;

    return {
      accelerate: { count: accelerate, percentage: accelerate / total },
      nominal: { count: nominal, percentage: nominal / total },
      decelerate: { count: decelerate, percentage: decelerate / total },
      total
    };
  }

  private async storeRUCResults(
    results: Map<string, RUCResult>,
    scheduleId: string
  ): Promise<void> {
    const records = Array.from(results.values()).map(result => ({
      assetId: result.assetId,
      scheduleId,
      category: result.category,
      ratio: result.ratio,
      deviation: result.deviation,
      absoluteDeviation: result.absoluteDeviation,
      calculatedAt: result.calculatedAt
    }));

    await this.rucRepo.createBatch(records);
  }
}
