### Scheduled RUC Calculation

```typescript
// jobs/ruc-calculation.job.ts
export class RUCCalculationJob {
  constructor(
    private readonly rucService: RUCService,
    private readonly alertService: AlertService,
    private readonly notificationService: NotificationService
  ) {}

  @Cron('0 6 * * *')  // Daily at 6 AM
  async runDailyRUCCalculation(): Promise<void> {
    console.log('Starting daily RUC calculation...');

    try {
      const results = await this.rucService.calculateCurrentRUC();

      // Check for significant changes
      const alerts = await this.checkForAlerts(results);

      if (alerts.length > 0) {
        await this.alertService.createBatch(alerts);
        await this.notificationService.sendRUCAlerts(alerts);
      }

      console.log(`RUC calculation complete. ${results.size} assets processed.`);
    } catch (error) {
      console.error('RUC calculation failed:', error);
      throw error;
    }
  }

  private async checkForAlerts(
    results: Map<string, RUCResult>
  ): Promise<RUCAlert[]> {
    const alerts: RUCAlert[] = [];

    // Get previous RUC results for comparison
    const previousResults = await this.rucService.getPreviousResults();

    for (const [assetId, current] of results) {
      const previous = previousResults.get(assetId);

      // Alert on category change
      if (previous && previous.category !== current.category) {
        alerts.push({
          type: 'category_change',
          assetId,
          previousCategory: previous.category,
          currentCategory: current.category,
          ratio: current.ratio,
          severity: this.calculateSeverity(previous, current)
        });
      }

      // Alert on high deviation
      if (Math.abs(current.deviation) > 0.20) {
        alerts.push({
          type: 'high_deviation',
          assetId,
          category: current.category,
          deviation: current.deviation,
          severity: Math.abs(current.deviation) > 0.30 ? 'critical' : 'warning'
        });
      }
    }

    return alerts;
  }
}
