## RUC-Based Schedule Adjustment

### Automatic Adjustment Rules

```typescript
interface RUCAdjustmentRule {
  category: RUCCategory;
  minRatio: number;
  maxRatio: number;
  periodAdjustment: number;  // Positive = move later, negative = move earlier
}

const defaultAdjustmentRules: RUCAdjustmentRule[] = [
  // ACCELERATE: Move maintenance earlier
  { category: RUCCategory.ACCELERATE, minRatio: 1.10, maxRatio: 1.20, periodAdjustment: -1 },
  { category: RUCCategory.ACCELERATE, minRatio: 1.20, maxRatio: 1.30, periodAdjustment: -2 },
  { category: RUCCategory.ACCELERATE, minRatio: 1.30, maxRatio: Infinity, periodAdjustment: -3 },

  // DECELERATE: Move maintenance later
  { category: RUCCategory.DECELERATE, minRatio: 0.80, maxRatio: 0.90, periodAdjustment: 1 },
  { category: RUCCategory.DECELERATE, minRatio: 0.70, maxRatio: 0.80, periodAdjustment: 2 },
  { category: RUCCategory.DECELERATE, minRatio: 0, maxRatio: 0.70, periodAdjustment: 3 }
];

function calculateAdjustment(
  rucResult: RUCResult,
  rules: RUCAdjustmentRule[]
): number {
  const applicableRule = rules.find(
    rule => rule.category === rucResult.category &&
            rucResult.ratio >= rule.minRatio &&
            rucResult.ratio < rule.maxRatio
  );

  return applicableRule?.periodAdjustment ?? 0;
}
```

### Schedule Adjustment Service

```typescript
// services/ruc-adjustment.service.ts
export class RUCAdjustmentService {
  async proposeAdjustments(
    scheduleId: string
  ): Promise<ProposedAdjustment[]> {
    const schedule = await this.scheduleRepo.getWithEvents(scheduleId);
    const rucResults = await this.rucService.calculateCurrentRUC();

    const proposals: ProposedAdjustment[] = [];

    for (const event of schedule.events) {
      if (event.status !== 'scheduled') continue;

      const ruc = rucResults.get(event.assetId);
      if (!ruc || ruc.category === RUCCategory.NOMINAL) continue;

      const adjustment = calculateAdjustment(ruc, defaultAdjustmentRules);
      if (adjustment === 0) continue;

      const newPeriod = event.scheduledPeriod + adjustment;

      // Check if adjustment is within allowed window
      if (newPeriod < event.earliestPeriod || newPeriod > event.latestPeriod) {
        continue;  // Cannot adjust outside window
      }

      proposals.push({
        eventId: event.id,
        assetId: event.assetId,
        currentPeriod: event.scheduledPeriod,
        proposedPeriod: newPeriod,
        rucCategory: ruc.category,
        rucRatio: ruc.ratio,
        adjustment,
        reason: this.generateReason(ruc, adjustment)
      });
    }

    // Sort by priority (higher deviation = higher priority)
    proposals.sort((a, b) =>
      Math.abs(b.rucRatio - 1) - Math.abs(a.rucRatio - 1)
    );

    return proposals;
  }

  async applyAdjustments(
    scheduleId: string,
    adjustmentIds: string[]
  ): Promise<AdjustmentResult> {
    const proposals = await this.proposeAdjustments(scheduleId);

    const toApply = proposals.filter(p => adjustmentIds.includes(p.eventId));

    // Validate adjustments don't violate capacity
    const validation = await this.validateAdjustments(scheduleId, toApply);

    if (!validation.valid) {
      return {
        success: false,
        errors: validation.errors
      };
    }

    // Apply in transaction
    await this.scheduleRepo.transaction(async (tx) => {
      for (const adj of toApply) {
        await this.scheduleRepo.updateEvent(adj.eventId, {
          scheduledPeriod: adj.proposedPeriod,
          originalPeriod: adj.currentPeriod,
          adjustmentReason: adj.reason,
          adjustmentType: 'ruc_based',
          adjustedAt: new Date()
        }, tx);
      }
    });

    return {
      success: true,
      adjustedCount: toApply.length
    };
  }

  private generateReason(ruc: RUCResult, adjustment: number): string {
    const direction = adjustment < 0 ? 'earlier' : 'later';
    const deviation = ((ruc.ratio - 1) * 100).toFixed(1);

    return `RUC ${ruc.category}: Asset usage ${deviation}% ` +
           `${ruc.ratio > 1 ? 'above' : 'below'} plan. ` +
           `Moving maintenance ${Math.abs(adjustment)} period(s) ${direction}.`;
  }
}
