## RUC Analytics

### Dashboard Data

```typescript
interface RUCDashboardData {
  currentDistribution: RUCDistribution;
  trendByCategory: CategoryTrend[];
  topAccelerating: AssetRUCSummary[];
  topDecelerating: AssetRUCSummary[];
  historicalTrend: RUCHistoricalPoint[];
}

interface CategoryTrend {
  category: RUCCategory;
  currentCount: number;
  previousCount: number;
  change: number;
  changePercentage: number;
}

interface AssetRUCSummary {
  assetId: string;
  assetName: string;
  category: RUCCategory;
  ratio: number;
  deviation: number;
  trend: 'improving' | 'worsening' | 'stable';
  daysSinceChange: number;
}

async function getRUCDashboardData(
  rucService: RUCService
): Promise<RUCDashboardData> {
  const [
    currentDistribution,
    previousDistribution,
    currentResults,
    history
  ] = await Promise.all([
    rucService.getRUCDistribution(),
    rucService.getRUCDistribution(addDays(new Date(), -7)),
    rucService.calculateCurrentRUC(),
    rucService.getHistoricalDistribution(30)
  ]);

  // Calculate trends
  const trendByCategory: CategoryTrend[] = [
    RUCCategory.ACCELERATE,
    RUCCategory.NOMINAL,
    RUCCategory.DECELERATE
  ].map(category => {
    const current = currentDistribution[category.toLowerCase()].count;
    const previous = previousDistribution[category.toLowerCase()].count;
    return {
      category,
      currentCount: current,
      previousCount: previous,
      change: current - previous,
      changePercentage: previous > 0 ? (current - previous) / previous : 0
    };
  });

  // Get top accelerating/decelerating
  const resultArray = Array.from(currentResults.values());

  const topAccelerating = resultArray
    .filter(r => r.category === RUCCategory.ACCELERATE)
    .sort((a, b) => b.ratio - a.ratio)
    .slice(0, 10);

  const topDecelerating = resultArray
    .filter(r => r.category === RUCCategory.DECELERATE)
    .sort((a, b) => a.ratio - b.ratio)
    .slice(0, 10);

  return {
    currentDistribution,
    trendByCategory,
    topAccelerating: await enrichWithAssetData(topAccelerating),
    topDecelerating: await enrichWithAssetData(topDecelerating),
    historicalTrend: history
  };
}
